// Extract data from webhook
const jobDescription = $input.first().json.body.jobDescription;
const jobTitle = $input.first().json.body.jobTitle || 'Unbenannte Stelle';
const candidates = $input.first().json.body.candidates || [];

// Create one item per candidate for processing
const items = candidates.map(candidate => ({
  json: {
    candidate,
    jobDescription,
    jobTitle
  }
}));

return items;

