const items = $input.all();
const results = [];

for (const item of items) {
  const candidate = item.json.candidate || {};
  let ollamaResponse = item.json.response || '';

  // Try to parse the LLM response
  let score = 0;
  let summary = 'Bewertung konnte nicht durchgeführt werden.';
  let strengths = [];
  let weaknesses = [];

  try {
    // Extract JSON from response (handle markdown code blocks)
    let jsonStr = ollamaResponse;
    const jsonMatch = ollamaResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      jsonStr = jsonMatch[0];
    }
    const parsed = JSON.parse(jsonStr);
    score = Math.min(1, Math.max(0, parseFloat(parsed.score) || 0));
    summary = parsed.summary || summary;
    strengths = parsed.strengths || [];
    weaknesses = parsed.weaknesses || [];
  } catch (e) {
    // If parsing fails, try to extract score from text
    const scoreMatch = ollamaResponse.match(/(\d+\.\d+)/);
    if (scoreMatch) {
      score = Math.min(1, Math.max(0, parseFloat(scoreMatch[1])));
    }
    summary = 'Score wurde aus der LLM-Antwort extrahiert. Details nicht verfügbar.';
  }

  results.push({
    candidateId: candidate.id,
    candidateName: candidate.name,
    score: Math.round(score * 100) / 100,
    summary,
    strengths,
    weaknesses
  });
}

// Sort by score descending
results.sort((a, b) => b.score - a.score);

return [{ json: { results, matchedAt: new Date().toISOString() } }];
